class Solution:
    def mergeTriplets(self, triplets, target):
        """
        :type triplets: List[List[int]]
        :type target: List[int]
        :rtype: bool
        """
        x, y, z = target
        got = [False, False, False]

        for a, b, c in triplets:
            # Can only use this triplet if all elements <= target
            if a <= x and b <= y and c <= z:
                if a == x:
                    got[0] = True
                if b == y:
                    got[1] = True
                if c == z:
                    got[2] = True

        return all(got)
